/**통합 게시판코멘트 리스트*/
SELECT a.* FROM (
	SELECT a.*
	,(SELECT USER_MEM_LVL FROM t_user_info WHERE USER_ID=a.REG_ID) USER_MEM_LVL
	FROM t_lecture_board_comment a
	WHERE B_IDX=#{bIdx}
	and status = #{status}
	ORDER BY G_IDX
	,SUBSTRING_INDEX(SUBSTRING_INDEX(G_ORD,':',1),':',-1)+0
	,SUBSTRING_INDEX(SUBSTRING_INDEX(G_ORD,':',2),':',-1)+0 
	,SUBSTRING_INDEX(SUBSTRING_INDEX(G_ORD,':',3),':',-1)+0  
	,SUBSTRING_INDEX(SUBSTRING_INDEX(G_ORD,':',4),':',-1)+0  
) a

mapper.update:
/** 통합게시판코멘트 수정 */
UPDATE t_lecture_board_comment 
SET
	CONTENT=#{content}
	,MOD_DT=#{modDt}
WHERE
	IDX=#{idx}

/** 통합게시판 답글관련 정보 수정 */
UPDATE t_lecture_board_comment 
SET	
	G_IDX=#{gIdx},
	G_ORD=#{gOrd},
	G_LVL=#{gLvl}
WHERE
	IDX=#{idx}

/** 통합게시판 답글관련 정보 수정 */
UPDATE t_lecture_board_comment 
SET	
	status=#{status}
WHERE
	IDX=#{idx}
